var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。","ENG":"that you'll be with it, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called it to your office. It said it'd be here soon.","TWN":"做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"사장님께선 파일럿이 되어보신 적이 있으십니까?","JPN":"社長は、パイロットの経験はありますか？","ENG":" Have you ever piloted a plane before?","TWN":"老闆，您當過駕駛員嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"영상매체를 통해 제가 학습한 바로는, 파일럿이 있을 때 기체도 비로소 진정한 잠재력을 발휘하게 된다고 합니다.","JPN":"映像メディアで学習した内容によれば、パイロットが乗り込んでこそ、機体に眠っている真のポテンシャルが発揮されるものだそうです。","ENG":" From what I've learned via the video archives, aircraft can perform at their true potential when there is a pilot.","TWN":"我從影片媒體中學習到，有駕駛員時，機體才能發揮出真正的潛力。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"기체가 스스로를 움직이는 것이 아닌, 파일럿이 기체와 한 몸이 되어 움직이는 것.","JPN":"機体が自ら動くのではなく、パイロットと機体が渾然一体となって動くんです。","ENG":" A fuselage moving in conjunction with the pilot, instead of following auto-pilot protocols...","TWN":"不是機體自己行動，而是駕駛員以機體為己身來行動。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"그건 과연 어떤 느낌일까요?","JPN":"それはいったいどんな感じなんでしょう？","ENG":" I wonder what that feels like?","TWN":"那究竟是什麼感覺呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"저의 설계자께서는 그런 걸 두고 로망이라 부른다고 하더군요.","JPN":"私の設計者がおっしゃったのですが、そういうことを、ロマンと呼ぶんだそうです。","ENG":" My designer once said that's what humans call a dream.","TWN":"我的設計師稱之為浪漫。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"인공지능이 보편화되지 않았던 시절엔 모두가 그런 로망을 알고 있었던 거겠죠.","JPN":"人工知能が普及していなかった頃は、みんながそういったロマンを理解していたのでしょうね。","ENG":" I suppose everyone had such a dream when artificial intelligence wasn't as ubiquitous.","TWN":"在人工智慧尚未普及的時代，無論是誰都知道這種浪漫吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"저도 한때는 이런 고도화된 인격 대신 파일럿을 태울 수 있기를 바랬던 적이 있었습니다.","JPN":"私にも、こういった高度化された人格の代わりに、パイロットを乗せられたらと願っていた頃がありました。","ENG":" I too once aspired to host a human pilot instead of this sophisticated A.I. personality suite.","TWN":"曾經，我也希望可以乘載駕駛員，而不是擁有這種高度發展的人格。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"하지만 어째서일까요.","JPN":"でも、どうしてなんでしょう。","ENG":" But for some reason...","TWN":"不過是為什麼呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"사장님을 만난 뒤로 그런 저의 바램은 꽤 오랫동안 재고된 적이 없더군요.","JPN":"社長に会って以来、私のそうした願いは、何故だか長い間忘れ去られていました。","ENG":" Ever since I met you, I had not updated my desire.","TWN":"遇到老闆以後，我很久沒有重新想過那種願望了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"정답은 렌즈의 사각에 있었습니다.","JPN":"その理由は、レンズの死角にありました。","ENG":" The answer was hiding in the blind spot of my lenses.","TWN":"正確答案就在鏡頭盲區。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"제가 그토록 찾던 로망이 너무 가까운 곳에 있었기 때문에 오히려 눈치채지 못한 것이죠.","JPN":"私が求めてやまなかったロマンは、あまりにも近くに存在していました。それゆえに気づけずにいたのです。","ENG":" The dream I've been seeking for so long was already near me, so I simply didn't notice it.","TWN":"因為我一直在尋找的浪漫就近在咫尺，反而讓我沒有查覺到。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"자고로! 파일럿과 기체란, 서로를 믿고 의지하는 상호의존적 관계!","JPN":"曰く！パイロットと機体とは、信じ合い、頼り合う、相互依存的な関係である！","ENG":" You see! A pilot and an aircraft must be mutually trusting and dependent!","TWN":"自古以來！駕駛員和機體，就是彼此信任，互相依靠的關係！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"로망은 배터리의 전극처럼 물리적으로 이어지는 것이 아닌!","JPN":"ロマンはバッテリーの電極のように物理的に繋がるものではなく！","ENG":" The connection between them is not something physical, like the one between the battery and the terminal!","TWN":"浪漫不是像電池的電極那樣，以物理方式連接的東西！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"마음이란 에너지로 이어지는 것!","JPN":"心というエネルギーによって繋がるものである！","ENG":" What's important is the connection between their hearts!","TWN":"而是靠心靈連接的能量！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"그 마음이 둘을 이어줄 때! 둘은 비로소 하나!","JPN":"その心が二つを繋ぐ時！　それらは二つで一つ！","ENG":" When two hearts are bound, they become one!","TWN":"當兩人心意相通時！兩人才能真正的合為一體！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"비록 파일럿이 제 몸 속에 없더라도, 로망은 얼마든지 성립될 수 있었던 겁니다!","JPN":"たとえパイロットが私の機体内にいなくとも、ロマンはいくらでも成立できたのです！","ENG":" The pilot didn't have to be inside me, to achieve my dream!","TWN":"就算駕駛員不在我的機體內，浪漫不管怎麼樣都可以成立！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"바로 사장님과 저처럼!","JPN":"まさに、社長と私のように！","ENG":" Like you and me!","TWN":"就像老闆和我一樣！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};